INSERT INTO cards_card VALUES(64,'base1-64','Starmie','Pokémon','["Stage 1"]',60,'Common','64','Keiji Kinebuchi','Its central core glows with the seven colors of the rainbow. Some people value this core as a gem.','https://images.pokemontcg.io/base1/64.png','https://images.pokemontcg.io/base1/64_hires.png','Staryu','["Colorless"]','2026-05-10 15:18:41.045159','2026-05-10 15:21:43.791989',1);
INSERT INTO cards_card VALUES(65,'base1-65','Staryu','Pokémon','["Basic"]',40,'Common','65','Keiji Kinebuchi','An enigmatic Pokémon that can effortlessly regenerate any appendage it loses in battle.','https://images.pokemontcg.io/base1/65.png','https://images.pokemontcg.io/base1/65_hires.png','','["Colorless"]','2026-05-10 15:18:41.051485','2026-05-10 15:21:43.815262',1);
INSERT INTO cards_card VALUES(66,'base1-66','Tangela','Pokémon','["Basic"]',50,'Common','66','Mitsuhiro Arita','Its whole body is swathed with wide vines that are similar to seaweed. These vines shake as it walks.','https://images.pokemontcg.io/base1/66.png','https://images.pokemontcg.io/base1/66_hires.png','','["Colorless", "Colorless"]','2026-05-10 15:18:41.058117','2026-05-10 15:21:43.836496',1);
