PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE IF NOT EXISTS "cards_cardset" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "set_id" varchar(50) NOT NULL UNIQUE, "name" varchar(200) NOT NULL, "series" varchar(200) NOT NULL, "printed_total" integer NOT NULL, "total" integer NOT NULL, "release_date" datetime NULL, "symbol_url" varchar(200) NOT NULL, "logo_url" varchar(200) NOT NULL);
CREATE TABLE IF NOT EXISTS "cards_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(50) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "cards_price" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "tcg_low" decimal NULL, "tcg_mid" decimal NULL, "tcg_high" decimal NULL, "tcg_market" decimal NULL, "cm_avg1" decimal NULL, "cm_avg7" decimal NULL, "cm_avg30" decimal NULL, "update_at" date NOT NULL, "card_id" bigint NOT NULL REFERENCES "cards_card" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "cards_resistance" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "value" varchar(10) NOT NULL, "card_id" bigint NOT NULL REFERENCES "cards_card" ("id") DEFERRABLE INITIALLY DEFERRED, "type_id" bigint NOT NULL REFERENCES "cards_type" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "cards_cardtype" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "order" integer NOT NULL, "card_id" bigint NOT NULL REFERENCES "cards_card" ("id") DEFERRABLE INITIALLY DEFERRED, "type_id" bigint NOT NULL REFERENCES "cards_type" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "cards_card" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "card_id" varchar(50) NOT NULL UNIQUE, "name" varchar(200) NOT NULL, "supertype" varchar(50) NOT NULL, "subtypes" text NOT NULL CHECK ((JSON_VALID("subtypes") OR "subtypes" IS NULL)), "hp" integer NULL, "rarity" varchar(50) NOT NULL, "card_number" varchar(20) NOT NULL, "artist" varchar(200) NOT NULL, "flavor_text" text NOT NULL, "image_small" varchar(200) NOT NULL, "image_large" varchar(200) NOT NULL, "evolves_from" varchar(200) NOT NULL, "retreat_cost" text NOT NULL CHECK ((JSON_VALID("retreat_cost") OR "retreat_cost" IS NULL)), "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "card_set_id" bigint NULL REFERENCES "cards_cardset" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "cards_weakness" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "value" varchar(10) NOT NULL, "card_id" bigint NOT NULL REFERENCES "cards_card" ("id") DEFERRABLE INITIALLY DEFERRED, "type_id" bigint NOT NULL REFERENCES "cards_type" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "cards_attack" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL, "converted_cost" integer NOT NULL, "cost" text NOT NULL CHECK ((JSON_VALID("cost") OR "cost" IS NULL)), "description" text NOT NULL, "order" integer NOT NULL, "card_id" bigint NOT NULL REFERENCES "cards_card" ("id") DEFERRABLE INITIALLY DEFERRED, "damage" varchar(20) NOT NULL);
DELETE FROM sqlite_sequence;
